)

fun Headers.toMap(): Map<String, List<String>> {
    val map = mutableMapOf<String, MutableList<String>>()
    for (i in 0 until size) {
        val name = name(i)
        val value = value(i)
        map.getOrPut(name) { mutableListOf() }.add(value)
    }
    return map
}